mapper.select:
SELECT GOAL.goal_id, GOAL.user_id, GOAL.goal_title, GOAL.goal_content, GOAL.start_date, GOAL.target_date, GOAL.end_date, GOAL.category_id, GCT.category_nm, GOAL.reg_id, GOAL.reg_dt, GOAL.mod_id, GOAL.mod_dt FROM tb_goal GOAL JOIN tb_goal_category GCT ON GCT.category_id = GOAL.category_id AND GCT.use_yn = 'Y' WHERE user_id = #{userId}
AND TO_CHAR(start_date, 'YYYY') = #{yyyy}
AND TO_CHAR(start_date, 'MM') = #{mm}
AND category_id = #{categoryId}
AND status = #{status}
order by start_date desc, end_date;

SELECT category_id, category_nm
FROM tb_goal_category
WHERE USE_YN = 'Y';

SELECT  item_frequency_id, item_frequency_nm
FROM    public.tb_goal_item_frequency
WHERE   USE_YN = 'Y';
